        Color(red: 0.20, green: 0.45, blue: 0.95),
        Color(red: 0.00, green: 0.56, blue: 0.44),
        Color(red: 0.88, green: 0.42, blue: 0.10),
        Color(red: 0.62, green: 0.34, blue: 0.88),
        Color(red: 0.86, green: 0.20, blue: 0.36),
